```mlir
  hw.module @Example(%clock: i1, %foo: !hw.array<3xi2>, %bar: !hw.array<4xi2>) -> (out: !hw.array<3xi1>) {
    %r = sv.reg {hw.verilogName = "r"} : !hw.inout<array<3xi1>>
    sv.always posedge %clock {
      %c1_i2 = hw.constant 1 : i2
      %c-1_i2 = hw.constant -1 : i2
      %c0_i2 = hw.constant 0 : i2
      sv.for %i = %c0_i2 to %c-1_i2 step %c1_i2 : i2 {
        %1 = sv.logic {hw.verilogName = "_GEN"} : !hw.inout<array<3xi2>>
        %2 = sv.logic {hw.verilogName = "_GEN_0"} : !hw.inout<array<3xi2>>
        %3 = hw.aggregate_constant [-2 : i2, 1 : i2, 0 : i2] : !hw.array<3xi2>
        sv.bpassign %1, %3 : !hw.array<3xi2>
        %4 = hw.aggregate_constant [-1 : i2, -2 : i2, 1 : i2] : !hw.array<3xi2>
        sv.bpassign %2, %4 : !hw.array<3xi2>
        %5 = sv.read_inout %2 : !hw.inout<array<3xi2>>
        %6 = hw.array_get %5[%i] : !hw.array<3xi2>, i2
        %7 = sv.read_inout %1 : !hw.inout<array<3xi2>>
        %8 = hw.array_get %7[%i] : !hw.array<3xi2>, i2
        %9 = hw.array_get %bar[%6] : !hw.array<4xi2>, i2
        %10 = hw.array_get %foo[%8] : !hw.array<3xi2>, i2
        %11 = comb.xor bin %9, %10 : i2
        %12 = comb.icmp bin eq %11, %8 : i2
        %13 = sv.array_index_inout %r[%i] : !hw.inout<array<3xi1>>, i2
        sv.passign %13, %12 : i1
      } {hw.verilogName = "i", sv.attributes = [#sv.attribute<"SV_FOR_LOOP", emitAsComment>]}
    }
    %0 = sv.read_inout %r : !hw.inout<array<3xi1>>
    hw.output %0 : !hw.array<3xi1>
  }
```
is currently lowered into
```verilog
// Generated by CIRCT firtool-1.43.0-99-g7e99cc22d-dirty
module Example(
  input             clock,
  input  [2:0][1:0] foo,
  input  [3:0][1:0] bar,
  output [2:0]      out
);

  reg [2:0] r;
  always @(posedge clock) begin
    for (logic [1:0] i = 2'h0; i < 2'h3; i += 2'h1) begin
      automatic logic [2:0][1:0] _GEN = '{2'h2, 2'h1, 2'h0};
      automatic logic [2:0][1:0] _GEN_0 = '{2'h3, 2'h2, 2'h1};
      r[i] <= (bar[_GEN_0[i]] ^ foo[_GEN[i]]) == _GEN[i];
    end
  end // always @(posedge)
  assign out = r;
endmodule
```
But we can canonicalize the above into:
```verilog
  always @(posedge clock) begin
    for (logic [1:0] i = 2'h0; i < 2'h3; i += 2'h1) begin
      r[i] <= (bar[i+1] ^ foo[i]) == i;
    end
  end // always @(posedge)
